import { describe, test, expect, beforeAll } from 'jest';
import { DigestGenerator } from '../../src/digest/digest-generator';

describe('Digest Generator Template Rendering Contract', () => {
  let digestGenerator: DigestGenerator;

  beforeAll(() => {
    // This will fail until DigestGenerator is implemented
    digestGenerator = new DigestGenerator();
  });

  test('POST /digests/generate - should generate daily digest with default template', async () => {
    const generateRequest = {
      digestType: 'daily',
      dateRange: {
        start: '2024-01-15T00:00:00Z',
        end: '2024-01-15T23:59:59Z',
      },
      recipientEmail: 'user@example.com',
      templateName: 'default',
      customOptions: {
        includeFullContent: false,
        maxEmailsPerCategory: 50,
        sortBy: 'date',
        groupByThread: true,
      },
    };

    // This should fail until the digest generation method is implemented
    const result = await digestGenerator.generateDigest(generateRequest);

    // Contract assertions - these define what the implementation must return
    expect(result).toMatchObject({
      digestId: expect.stringMatching(/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/),
      generatedAt: expect.any(String),
      digestType: 'daily',
      totalEmailCount: expect.any(Number),
      categoryCounts: expect.any(Object),
      templateUsed: 'default',
      htmlSize: expect.any(Number),
      generationTimeMs: expect.any(Number),
      preview: expect.objectContaining({
        subject: expect.any(String),
        snippet: expect.any(String),
      }),
    });

    // Validate digest structure
    expect(result.totalEmailCount).toBeGreaterThanOrEqual(0);
    expect(result.htmlSize).toBeGreaterThan(0);
    expect(result.generationTimeMs).toBeGreaterThan(0);
    expect(result.preview.snippet).toHaveLength(200); // First 200 chars
  });

  test('POST /digests/generate - should support weekly digest with category filtering', async () => {
    const weeklyRequest = {
      digestType: 'weekly',
      dateRange: {
        start: '2024-01-08T00:00:00Z',
        end: '2024-01-14T23:59:59Z',
      },
      categories: ['receipts', 'newsletters', 'notifications'],
      recipientEmail: 'user@example.com',
      templateName: 'weekly-summary',
      customOptions: {
        includeFullContent: true,
        maxEmailsPerCategory: 25,
        sortBy: 'confidence',
        groupByThread: false,
      },
    };

    const result = await digestGenerator.generateDigest(weeklyRequest);

    expect(result.digestType).toBe('weekly');
    expect(result.templateUsed).toBe('weekly-summary');

    // Validate category filtering was applied
    const categoryNames = Object.keys(result.categoryCounts);
    expect(categoryNames).toEqual(expect.arrayContaining(['receipts', 'newsletters', 'notifications']));
  });

  test('POST /digests/generate - should handle on-demand digest generation', async () => {
    const onDemandRequest = {
      digestType: 'on_demand',
      dateRange: {
        start: '2024-01-01T00:00:00Z',
        end: '2024-01-31T23:59:59Z',
      },
      recipientEmail: 'user@example.com',
      customOptions: {
        includeFullContent: false,
        maxEmailsPerCategory: 100,
        sortBy: 'urgency',
      },
    };

    const result = await digestGenerator.generateDigest(onDemandRequest);

    expect(result.digestType).toBe('on_demand');
    expect(result.templateUsed).toBe('default'); // Default template when not specified
  });

