    expect(result).toMatchObject({
      id: digestId,
      generatedAt: expect.any(String),
      digestType: expect.stringMatching(/^(daily|weekly|on_demand)$/),
      recipientEmail: expect.stringMatching(/^[^\s@]+@[^\s@]+\.[^\s@]+$/),
      dateRange: expect.objectContaining({
        start: expect.any(String),
        end: expect.any(String),
      }),
      categories: expect.arrayContaining([
        expect.objectContaining({
          categoryName: expect.any(String),
          emailCount: expect.any(Number),
          emails: expect.arrayContaining([
            expect.objectContaining({
              emailId: expect.any(String),
              subject: expect.any(String),
              from: expect.objectContaining({
                email: expect.any(String),
                raw: expect.any(String),
              }),
              date: expect.any(String),
              snippet: expect.any(String),
              confidence: expect.any(Number),
              urgency: expect.stringMatching(/^(low|medium|high)$/),
            }),
          ]),
          priority: expect.any(Number),
          templateData: expect.any(Object),
        }),
      ]),
      totalEmailCount: expect.any(Number),
      templateUsed: expect.any(String),
